using Pkg 
Pkg.activate("UTrack")
using UTrack

# full optimization without any XUR (random initial pulses)
p = OptimizationParameters(NGens=200, NPulses=12, NCycles=20, NSteps=10, NGensXUR=0)
UTrack.new_optimization_no_xur("examples/G10x20",p)
UTrack.continue_optimization("examples/G10x20")

# faster optimization using XUR
p = OptimizationParameters(NGens=50, NPulses=12, NCycles=20, NSteps=10, NGensXUR=50)
UTrack.new_optimization("examples/G10x20-xur",p)

# smaller robustness region
p = OptimizationParameters(NGens=50, NPulses=12, NCycles=20, NSteps=10, NGensXUR=50, Detuning=0.1, RabiFDev=0.1)
UTrack.new_optimization("results/examples/G10x20-small",p)


